app.MapOpenApi();

if (app.Environment.IsDevelopment())
{
    app.UseSwaggerUI(o => o.SwaggerEndpoint("/openapi/v1.json", "Products API v1"));
}

app.UseHttpsRedirection();
app.MapControllers();

app.Run();

